import os

def delete_uploaded_file(filename):
    uploads_dir = 'uploads'
    file_path = os.path.join(uploads_dir, filename)

    if os.path.isfile(file_path):
        os.remove(file_path)
        return f"{filename} has been deleted."
    else:
        return "File not found."